#!/usr/bin/env -S npx ts-node -r tsconfig-paths/register
/**
 * Example: Submit a one-time job run
 *
 * This example demonstrates:
 * - Submitting a one-time job run (without creating a job definition)
 * - Waiting for job completion with progress updates
 * - Checking result state and output
 * - Using the Jobs Submit API
 *
 * Prerequisites:
 * - DATABRICKS_HOST environment variable
 * - Valid authentication (PAT, OAuth M2M, or other)
 *
 * Usage:
 *   npx ts-node examples/workspace/jobs/submit-job.ts
 */

import {WorkspaceClient, Time, TimeUnits} from "@databricks/sdk-experimental";

async function main() {
    const client = new WorkspaceClient({});

    const runName = `sdk-submit-example-${Date.now()}`;

    console.log(`Submitting one-time job run: ${runName}`);

    try {
        // Submit a one-time job run
        const waiter = await client.jobs.submit({
            run_name: runName,
            tasks: [
                {
                    task_key: "hello_task",
                    notebook_task: {
                        notebook_path: "/Shared/simple-notebook", // Adjust path as needed
                        source: "WORKSPACE",
                    },
                    new_cluster: {
                        spark_version: await client.clusters.selectSparkVersion(
                            {
                                latest: true,
                            }
                        ),
                        node_type_id: await client.clusters.selectNodeType({
                            minMemoryGb: 8,
                            minCores: 2,
                        }),
                        num_workers: 1,
                    },
                },
            ],
        });

        console.log(`✓ Job submitted successfully`);
        console.log(`  Run ID: ${waiter.run_id}`);

        // Wait for completion with progress updates
        console.log(`\nWaiting for job completion...`);

        const result = await waiter.wait({
            timeout: new Time(20, TimeUnits.minutes),
            onProgress: async (run) => {
                console.log(`  State: ${run.state?.life_cycle_state}`);
                if (run.state?.state_message) {
                    console.log(`  Message: ${run.state.state_message}`);
                }
            },
        });

        console.log(`\n✓ Job completed!`);
        console.log(`  Result State: ${result.state?.result_state}`);
        console.log(`  Life Cycle State: ${result.state?.life_cycle_state}`);

        if (result.state?.result_state === "SUCCESS") {
            console.log(`  Status: ✓ Job succeeded`);
        } else {
            console.log(
                `  Status: ✗ Job ${result.state?.result_state?.toLowerCase()}`
            );
        }

        console.log(
            `  Run URL: ${client.config.host}#job/${result.run_id}/run/1`
        );
    } catch (error) {
        console.error(`✗ Error:`, error);
        process.exit(1);
    }
}

main();
